import type {
	CategoryId,
	CriterionDefinition,
	CriterionId,
	MultiSelectScoringRule,
	NumericBand,
	ProfileDefinition,
	ProfileId,
	ScoreValue,
	ScoringRule,
} from "@portugal/domain-shared";
import { patchActiveScoringConfig } from "./plot-storage";

const clampScore = (value: number): ScoreValue =>
	Math.max(1, Math.min(5, Math.round(value))) as ScoreValue;
const clampWeight = (value: number): number =>
	Math.max(1, Math.min(10, Math.round(value)));

const defaultNumericBands = (): NumericBand[] => [
	{ maxExclusive: 10, score: 5 },
	{ maxExclusive: 20, minInclusive: 10, score: 3 },
	{ minInclusive: 20, score: 1 },
];

const defaultQualitativeMapping = (): Record<string, ScoreValue> => ({
	average: 3,
	excellent: 5,
	poor: 1,
});

const defaultMultiSelectMapping = (): Record<string, ScoreValue> => ({
	basic: 2,
	good: 4,
	premium: 5,
});

const defaultRuleForType = (type: ScoringRule["type"]): ScoringRule => {
	if (type === "numeric") {
		return {
			bands: defaultNumericBands(),
			type: "numeric",
		};
	}
	if (type === "qualitative") {
		return {
			mapping: defaultQualitativeMapping(),
			type: "qualitative",
		};
	}
	return {
		aggregation: "max",
		mapping: defaultMultiSelectMapping(),
		type: "multi_select",
	};
};

export const updateProfileField = async (
	profileId: ProfileId,
	field: keyof Pick<ProfileDefinition, "name" | "code" | "description">,
	value: string,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		profiles: cfg.profiles.map((profile) =>
			profile.id === profileId ? { ...profile, [field]: value } : profile,
		),
	}));
};

export const updateProfileWeight = async (
	profileId: ProfileId,
	criterionId: CriterionId,
	nextWeightValue: string,
): Promise<void> => {
	const parsedWeight = Number(nextWeightValue);
	if (!Number.isFinite(parsedWeight)) {
		return;
	}
	const normalizedWeight = clampWeight(parsedWeight);
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		profileWeights: {
			...cfg.profileWeights,
			[profileId]: {
				...(cfg.profileWeights[profileId] ?? {}),
				[criterionId]: normalizedWeight,
			},
		},
	}));
};

export const updateCategoryField = async (
	categoryId: CategoryId,
	field: keyof Pick<{ name: string; description: string }, "name" | "description">,
	value: string,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		categories: cfg.categories.map((category) =>
			category.id === categoryId ? { ...category, [field]: value } : category,
		),
	}));
};

export const updateCriterionField = async (
	criterionId: CriterionId,
	field: keyof Pick<
		CriterionDefinition,
		"name" | "description" | "measurementBasis" | "categoryId"
	>,
	value: string,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) =>
			criterion.id === criterionId ? { ...criterion, [field]: value } : criterion,
		),
	}));
};

export const updateCriterionRuleType = async (
	criterionId: CriterionId,
	type: ScoringRule["type"],
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) =>
			criterion.id === criterionId
				? {
						...criterion,
						rule: defaultRuleForType(type),
					}
				: criterion,
		),
	}));
};

export const updateNumericBand = async (
	criterionId: CriterionId,
	bandIndex: number,
	field: keyof Pick<NumericBand, "minInclusive" | "maxExclusive" | "score">,
	rawValue: string,
): Promise<void> => {
	const parsed = Number(rawValue);
	if (!Number.isFinite(parsed)) {
		return;
	}

	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId || criterion.rule.type !== "numeric") {
				return criterion;
			}
			const nextBands = criterion.rule.bands.map((band, index) => {
				if (index !== bandIndex) {
					return band;
				}
				if (field === "score") {
					return { ...band, score: clampScore(parsed) };
				}
				return { ...band, [field]: parsed };
			});
			return {
				...criterion,
				rule: {
					...criterion.rule,
					bands: nextBands,
				},
			};
		}),
	}));
};

export const addNumericBand = async (criterionId: CriterionId): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId || criterion.rule.type !== "numeric") {
				return criterion;
			}
			return {
				...criterion,
				rule: {
					...criterion.rule,
					bands: [...criterion.rule.bands, { score: 1 }],
				},
			};
		}),
	}));
};

export const removeNumericBand = async (
	criterionId: CriterionId,
	bandIndex: number,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId || criterion.rule.type !== "numeric") {
				return criterion;
			}
			return {
				...criterion,
				rule: {
					...criterion.rule,
					bands: criterion.rule.bands.filter((_, index) => index !== bandIndex),
				},
			};
		}),
	}));
};

export const updateOptionMapping = async (
	criterionId: CriterionId,
	oldKey: string,
	nextKey: string,
	nextScore: ScoreValue,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId) {
				return criterion;
			}
			if (
				criterion.rule.type !== "qualitative" &&
				criterion.rule.type !== "multi_select"
			) {
				return criterion;
			}
			const sanitizedKey = nextKey.trim().toLowerCase() || oldKey;
			const nextMapping = { ...criterion.rule.mapping };
			delete nextMapping[oldKey];
			nextMapping[sanitizedKey] = clampScore(nextScore);
			return {
				...criterion,
				rule: {
					...criterion.rule,
					mapping: nextMapping,
				},
			};
		}),
	}));
};

export const addOptionMapping = async (criterionId: CriterionId): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId) {
				return criterion;
			}
			if (
				criterion.rule.type !== "qualitative" &&
				criterion.rule.type !== "multi_select"
			) {
				return criterion;
			}
			return {
				...criterion,
				rule: {
					...criterion.rule,
					mapping: {
						...criterion.rule.mapping,
						[`option_${Object.keys(criterion.rule.mapping).length + 1}`]: 3,
					},
				},
			};
		}),
	}));
};

export const removeOptionMapping = async (
	criterionId: CriterionId,
	key: string,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId) {
				return criterion;
			}
			if (
				criterion.rule.type !== "qualitative" &&
				criterion.rule.type !== "multi_select"
			) {
				return criterion;
			}
			const nextMapping = { ...criterion.rule.mapping };
			delete nextMapping[key];
			return {
				...criterion,
				rule: {
					...criterion.rule,
					mapping: nextMapping,
				},
			};
		}),
	}));
};

export const updateMultiSelectAggregation = async (
	criterionId: CriterionId,
	aggregation: MultiSelectScoringRule["aggregation"],
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		criteria: cfg.criteria.map((criterion) => {
			if (criterion.id !== criterionId || criterion.rule.type !== "multi_select") {
				return criterion;
			}
			return {
				...criterion,
				rule: {
					...criterion.rule,
					aggregation,
				},
			};
		}),
	}));
};

