export const saveSnapshot = async (snapshot: AppSnapshot): Promise<void> => {
	await runTransaction<void>("readwrite", (store, resolve, reject) => {
		const request = store.put(snapshot, SNAPSHOT_KEY);
		request.onsuccess = () => resolve();
		request.onerror = () => reject(request.error);
	});
	if (typeof window !== "undefined") {
		syncRawMetricsOverlayFromPlots(snapshot.plots);
		window.dispatchEvent(new CustomEvent(SNAPSHOT_CHANGED_EVENT));
	}
};

/** Loads the latest snapshot, applies `patch` to `activeConfig`, and persists (fires {@link SNAPSHOT_CHANGED_EVENT}). */
export const patchActiveScoringConfig = async (
	patch: (config: ScoringConfig) => ScoringConfig,
): Promise<void> => {
	const latest = await loadSnapshot();
	await saveSnapshot({
		...latest,
		activeConfig: patch(latest.activeConfig),
	});
};

