import type {
	CategoryId,
	CategoryDefinition,
	CriterionDefinition,
	CriterionId,
	MultiSelectScoringRule,
	NumericBand,
	ProfileDefinition,
	ProfileId,
	ScoreValue,
	ScoringConfig,
	ScoringRule,
} from "@portugal/domain-shared";
import { patchActiveScoringConfig } from "./plot-storage";

const clampScore = (value: number): ScoreValue =>
	Math.max(1, Math.min(5, Math.round(value))) as ScoreValue;
const clampWeight = (value: number): number =>
	Math.max(1, Math.min(10, Math.round(value)));

const defaultNumericBands = (): NumericBand[] => [
	{ maxExclusive: 10, score: 5 },
	{ maxExclusive: 20, minInclusive: 10, score: 3 },
	{ minInclusive: 20, score: 1 },
];

const defaultQualitativeMapping = (): Record<string, ScoreValue> => ({
	average: 3,
	excellent: 5,
	poor: 1,
});

const defaultMultiSelectMapping = (): Record<string, ScoreValue> => ({
	basic: 2,
	good: 4,
	premium: 5,
});

const defaultRuleForType = (type: ScoringRule["type"]): ScoringRule => {
	if (type === "numeric") {
		return {
			bands: defaultNumericBands(),
			type: "numeric",
		};
	}
	if (type === "qualitative") {
		return {
			mapping: defaultQualitativeMapping(),
			type: "qualitative",
		};
	}
	return {
		aggregation: "max",
		mapping: defaultMultiSelectMapping(),
		type: "multi_select",
	};
};

export type CategoryCriteriaGroup = {
	category: CategoryDefinition | null;
	categoryId: string;
	criteria: CriterionDefinition[];
};

/** Order categories as in config; unknown category ids list after, each as its own group. */
export function groupCriteriaByCategory(
	config: Pick<ScoringConfig, "categories" | "criteria">,
): CategoryCriteriaGroup[] {
	const byCat = new Map<string, CriterionDefinition[]>();
	for (const criterion of config.criteria) {
		const list = byCat.get(criterion.categoryId) ?? [];
		list.push(criterion);
		byCat.set(criterion.categoryId, list);
	}

	const ordered: CategoryCriteriaGroup[] = [];
	for (const category of config.categories) {
		const criteria = byCat.get(category.id);
		if (criteria !== undefined && criteria.length > 0) {
			ordered.push({ category, categoryId: category.id, criteria });
			byCat.delete(category.id);
		}
	}
	for (const [categoryId, criteria] of byCat) {
		if (criteria.length > 0) {
			ordered.push({ category: null, categoryId, criteria });
		}
	}
	return ordered;
}

export const updateProfileField = async (
	profileId: ProfileId,
	field: keyof Pick<ProfileDefinition, "name" | "code" | "description">,
	value: string,
): Promise<void> => {
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		profiles: cfg.profiles.map((profile) =>
			profile.id === profileId ? { ...profile, [field]: value } : profile,
		),
	}));
};

export const updateProfileWeight = async (
	profileId: ProfileId,
	criterionId: CriterionId,
	nextWeightValue: string,
): Promise<void> => {
	const parsedWeight = Number(nextWeightValue);
	if (!Number.isFinite(parsedWeight)) {
		return;
	}
	const normalizedWeight = clampWeight(parsedWeight);
	await patchActiveScoringConfig((cfg) => ({
		...cfg,
		profileWeights: {
			...cfg.profileWeights,
			[profileId]: {
				...(cfg.profileWeights[profileId] ?? {}),
				[criterionId]: normalizedWeight,
			},
		},
	}));
};

export const updateCategoryField = async (
	categoryId: CategoryId,
