export const addNewProfile = async (): Promise<ProfileId | null> => {
	let createdId: ProfileId | null = null;
	await patchActiveScoringConfig((cfg) => {
		const existingIds = new Set(cfg.profiles.map((profile) => profile.id));
		let sequence = cfg.profiles.length + 1;
		let profileId: ProfileId = `P_${sequence}`;
		while (existingIds.has(profileId)) {
			sequence += 1;
			profileId = `P_${sequence}`;
		}
		createdId = profileId;

		const defaultWeights: Record<CriterionId, number> = {};
		for (const criterion of cfg.criteria) {
			defaultWeights[criterion.id] = 5;
		}

		return {
			...cfg,
			profileWeights: {
				...cfg.profileWeights,
				[profileId]: defaultWeights,
			},
			profiles: [
				...cfg.profiles,
				{
					code: `N${sequence}`,
					description: "Custom evaluation profile",
					id: profileId,
					name: `New profile ${sequence}`,
				},
			],
		};
	});
	return createdId;
};

export const addNewCriterion = async (): Promise<CriterionId | null> => {
	let createdId: CriterionId | null = null;
	await patchActiveScoringConfig((cfg) => {
		const existingIds = new Set(cfg.criteria.map((criterion) => criterion.id));
		let sequence = cfg.criteria.length + 1;
		let criterionId: CriterionId = `C${String(sequence).padStart(2, "0")}`;
		while (existingIds.has(criterionId)) {
			sequence += 1;
			criterionId = `C${String(sequence).padStart(2, "0")}`;
		}
		createdId = criterionId;

		const nextCriterion: CriterionDefinition = {
			categoryId: cfg.categories[0]?.id ?? "CAT_LOC",
			description: "Describe this criterion",
			id: criterionId,
			measurementBasis: "Custom scale",
			name: `New criterion ${sequence}`,
			rule: defaultRuleForType("numeric"),
		};

		const nextProfileWeights = Object.fromEntries(
			cfg.profiles.map((profile) => [
				profile.id,
				{
					...(cfg.profileWeights[profile.id] ?? {}),
					[criterionId]: 5,
				},
			]),
		) as ScoringConfig["profileWeights"];

		return {
			...cfg,
			criteria: [...cfg.criteria, nextCriterion],
			profileWeights: nextProfileWeights,
		};
	});
	return createdId;
};

