import { IconButton, Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@portugal/ui";
import { Info } from "lucide-react";

export type ScoringInfoIconButtonProps = {
	/** Hover / focus tooltip (keep concise). */
	tooltip: string;
	/** Accessible name for the control. */
	ariaLabel: string;
	/** Opens the stacked detail panel for this entity. */
	onOpenDetail: () => void;
};

export function ScoringInfoIconButton({
	tooltip,
	ariaLabel,
	onOpenDetail,
}: ScoringInfoIconButtonProps) {
	return (
		<TooltipProvider delayDuration={200}>
			<Tooltip>
				<TooltipTrigger asChild>
					<span className="inline-flex shrink-0">
						<IconButton
							type="button"
							icon={Info}
							aria-label={ariaLabel}
							variant="ghost"
							className="size-7 text-muted-foreground hover:text-foreground"
							onClick={(event) => {
								event.preventDefault();
								event.stopPropagation();
								onOpenDetail();
							}}
						/>
					</span>
				</TooltipTrigger>
				<TooltipContent side="top" className="max-w-xs text-left">
					{tooltip}
				</TooltipContent>
