import type {
	CategoryId,
	CriterionDefinition,
	CriterionId,
	PlotRawMetrics,
	ScoringConfig,
} from "@portugal/domain-shared";
import type { CriterionScores } from "@portugal/domain-shared/plot-scoring/scoring";
import {
	Collapsible,
	CollapsibleContent,
	CollapsibleTrigger,
} from "@portugal/ui";
import { PlotCriterionEditorCard } from "@portugal/ui-lib";
import { ChevronDown } from "lucide-react";

import { normalizeRawMetricInput } from "../lib/plot-storage";
import { groupCriteriaByCategory } from "../lib/scoring-config-mutations";
import { ScoringInfoIconButton } from "./scoring-info-icon-button";

function formatRawMetricValue(value: unknown): string {
	if (typeof value === "number") {
		return String(value);
	}
	if (typeof value === "string") {
		return value;
	}
	if (Array.isArray(value)) {
		return value.join(", ");
	}
	return "—";
}

function categoryTooltipText(
	category: { name: string; description: string } | null,
	categoryId: CategoryId,
): string {
	if (category) {
		const desc = category.description.trim();
		return desc.length > 0 ? `${category.name}. ${desc}` : category.name;
	}
	return `Category id ${categoryId}. This id is not listed under categories in the active config.`;
}

function criterionTooltipText(criterion: CriterionDefinition): string {
	const parts = [
		criterion.description.trim(),
		criterion.measurementBasis.trim(),
	].filter((s) => s.length > 0);
	return parts.length > 0 ? parts.join(" · ") : criterion.name;
}

export type PlotRawMetricsByCategoryReadProps = {
	mode: "read";
	config: ScoringConfig;
	plotRawMetrics: PlotRawMetrics;
	criterionScores: CriterionScores;
	onOpenCategory: (categoryId: CategoryId) => void;
	onOpenCriterion: (criterionId: CriterionId) => void;
};

export type PlotRawMetricsByCategoryEditProps = {
	mode: "edit";
	config: ScoringConfig;
	draftRawMetrics: PlotRawMetrics;
	setDraftRawMetrics: React.Dispatch<React.SetStateAction<PlotRawMetrics>>;
	criterionScores: CriterionScores;
	onOpenCategory: (categoryId: CategoryId) => void;
	onOpenCriterion: (criterionId: CriterionId) => void;
};

export type PlotRawMetricsByCategoryProps =
	| PlotRawMetricsByCategoryReadProps
	| PlotRawMetricsByCategoryEditProps;

export function PlotRawMetricsByCategory(props: PlotRawMetricsByCategoryProps) {
	const groups = groupCriteriaByCategory(props.config).filter(
		(g) => g.criteria.length > 0,
	);

	return (
		<div className="space-y-2">
			{groups.map((group) => {
				const categoryLabel =
					group.category?.name?.trim() || group.categoryId;
				return (
					<Collapsible key={group.categoryId} defaultOpen>
						<CollapsibleTrigger
							type="button"
							className="group flex w-full items-center gap-2 rounded-md border border-border/30 bg-muted/25 px-2 py-1.5 text-left text-xs transition-colors hover:bg-muted/40"
						>
							<ChevronDown className="size-3.5 shrink-0 text-muted-foreground transition-transform group-data-[state=open]:rotate-180" />
							<span className="min-w-0 flex-1 truncate font-semibold text-foreground">
								{categoryLabel}
							</span>
							<span className="tabular-nums text-muted-foreground">
								{group.criteria.length}{" "}
								{group.criteria.length === 1 ? "criterion" : "criteria"}
							</span>
							<ScoringInfoIconButton
								ariaLabel={`About category ${categoryLabel}`}
								tooltip={categoryTooltipText(group.category, group.categoryId)}
								onOpenDetail={() => props.onOpenCategory(group.categoryId)}
							/>
						</CollapsibleTrigger>
						<CollapsibleContent className="pt-2">
							<ul className="space-y-2 pl-1">
								{group.criteria.map((criterion) => (
									<li key={criterion.id}>
										{props.mode === "read" ? (
											<ReadCriterionRow
												criterion={criterion}
												raw={props.plotRawMetrics[criterion.id]}
												score={props.criterionScores[criterion.id]}
												onOpenCriterion={() =>
													props.onOpenCriterion(criterion.id)
												}
												tooltip={criterionTooltipText(criterion)}
											/>
										) : (
											<EditCriterionRow
												criterion={criterion}
												config={props.config}
												draftRawMetrics={props.draftRawMetrics}
												setDraftRawMetrics={props.setDraftRawMetrics}
												score={props.criterionScores[criterion.id]}
												onOpenCriterion={() =>
													props.onOpenCriterion(criterion.id)
												}
												tooltip={criterionTooltipText(criterion)}
											/>
										)}
									</li>
								))}
							</ul>
						</CollapsibleContent>
					</Collapsible>
				);
			})}
		</div>
	);
}

function ReadCriterionRow({
	criterion,
	raw,
	score,
	onOpenCriterion,
	tooltip,
}: {
	criterion: CriterionDefinition;
	raw: unknown;
	score: number | undefined;
	onOpenCriterion: () => void;
	tooltip: string;
}) {
	return (
		<div className="rounded-md bg-muted/30 px-2 py-1.5 text-xs ring-1 ring-border/15">
			<div className="flex flex-wrap items-baseline justify-between gap-2">
				<div className="flex min-w-0 flex-1 items-center gap-1">
					<span className="truncate font-medium text-foreground">
						{criterion.name}
					</span>
					<ScoringInfoIconButton
						ariaLabel={`About criterion ${criterion.name}`}
						tooltip={tooltip}
						onOpenDetail={onOpenCriterion}
					/>
				</div>
				<span className="tabular-nums text-score-high">
					Score: {score !== undefined ? `${score} / 5` : "—"}
				</span>
			</div>
			<div className="text-muted-foreground">{criterion.measurementBasis}</div>
			<div className="mt-0.5 font-mono text-[11px] text-foreground/90">
				{raw === undefined ? "—" : formatRawMetricValue(raw)}
			</div>
		</div>
	);
}

function EditCriterionRow({
	criterion,
	config,
	draftRawMetrics,
	setDraftRawMetrics,
	score,
	onOpenCriterion,
	tooltip,
}: {
	criterion: CriterionDefinition;
	config: ScoringConfig;
	draftRawMetrics: PlotRawMetrics;
	setDraftRawMetrics: React.Dispatch<React.SetStateAction<PlotRawMetrics>>;
	score: number | undefined;
	onOpenCriterion: () => void;
	tooltip: string;
}) {
	const currentValue = draftRawMetrics[criterion.id];
	return (
		<div className="space-y-1">
			<div className="flex items-center gap-1 px-0.5">
				<span className="min-w-0 flex-1 truncate text-xs font-medium text-foreground">
					{criterion.name}
				</span>
				<ScoringInfoIconButton
					ariaLabel={`About criterion ${criterion.name}`}
					tooltip={tooltip}
					onOpenDetail={onOpenCriterion}
				/>
			</div>
			<PlotCriterionEditorCard
				criterionId={criterion.id}
				criterionName={criterion.name}
				inputKind={
					criterion.rule.type === "numeric"
						? "numeric"
						: criterion.rule.type === "qualitative"
							? "qualitative"
							: "multi_select"
				}
				measurementBasis={criterion.measurementBasis}
				score={score}
				value={
					criterion.rule.type === "numeric"
						? typeof currentValue === "number"
							? String(currentValue)
							: ""
						: criterion.rule.type === "qualitative" && typeof currentValue === "string"
							? currentValue
							: ""
				}
				options={
					criterion.rule.type === "qualitative" || criterion.rule.type === "multi_select"
						? Object.keys(criterion.rule.mapping).map((label) => ({
								label,
								value: label,
							}))
						: []
				}
				selectedOptions={Array.isArray(currentValue) ? currentValue : []}
				onMultiSelectChange={(nextValues) => {
					if (criterion.rule.type !== "multi_select") {
						return;
					}
					setDraftRawMetrics((prev) => ({
						...prev,
						[criterion.id]: nextValues,
					}));
				}}
				onChange={(nextValue) => {
					const storedValue =
						criterion.rule.type === "numeric"
							? normalizeRawMetricInput(nextValue, criterion.id, config)
							: criterion.rule.type === "qualitative"
								? nextValue
								: Array.isArray(currentValue)
									? currentValue
									: [];
					setDraftRawMetrics((prev) => {
						const next = { ...prev };
						if (storedValue === undefined) {
							delete next[criterion.id];
						} else {
							next[criterion.id] = storedValue;
						}
						return next;
					});
				}}
			/>
		</div>
	);
}

