}: CategoryDetailPanelProps) {
	const categoryId =
		typeof categoryIdProp === "string" && categoryIdProp.length > 0
			? categoryIdProp
			: undefined;
	const { snapshot, loading, error } = usePanelSnapshot();
	const { openPanel } = usePanelsContext<typeof panelRegistry>();
	const { canManageData } = useAuth();

	const openCriterion = useCallback(
		(criterionId: CriterionId) => {
			openPanel(CRITERION_DETAIL_PANEL_TYPE, { criterionId });
		},
		[openPanel],
	);

	if (loading) {
		return (
			<DetailPanelShell title="Category" panelType={panelType}>
				<p className="text-muted-foreground">Loading…</p>
			</DetailPanelShell>
		);
	}

	if (error || !snapshot) {
		return (
			<DetailPanelShell title="Category" panelType={panelType}>
				<p className="text-destructive">{error ?? "No data."}</p>
			</DetailPanelShell>
		);
	}

	if (!categoryId) {
		return (
			<DetailPanelShell title="Category" panelType={panelType}>
				<p className="text-muted-foreground">No category selected.</p>
			</DetailPanelShell>
		);
	}

	const category = snapshot.activeConfig.categories.find((c) => c.id === categoryId);
	const criteria = snapshot.activeConfig.criteria.filter(
		(c) => c.categoryId === categoryId,
	);
	const title = category?.name?.trim() || categoryId;

	const persistName = (value: string) => {
		if (!canManageData || !category) {
			return;
		}
		void updateCategoryField(category.id as CategoryId, "name", value);
	};

	const persistDescription = (value: string) => {
		if (!canManageData || !category) {
			return;
		}
		void updateCategoryField(category.id as CategoryId, "description", value);
	};

	return (
		<DetailPanelShell title={title} panelType={panelType}>
			<dl className="grid gap-2 text-xs">
				<dt className="text-muted-foreground">Id</dt>
				<dd className="font-mono text-[11px]">{categoryId}</dd>
				{category ? (
					<>
						<dt className="text-muted-foreground">Name</dt>
						<dd className="text-foreground/90">
							{canManageData ? (
								<Label className="block">
									<Input
										value={category.name}
										onChange={(e) => persistName(e.target.value)}
										className="mt-0.5 font-sans text-sm"
									/>
								</Label>
							) : (
								category.name
							)}
						</dd>
						<dt className="text-muted-foreground">Description</dt>
						<dd className="text-foreground/90">
							{canManageData ? (
								<Label className="block">
									<Input
										value={category.description}
										onChange={(e) => persistDescription(e.target.value)}
										className="mt-0.5 font-sans text-sm"
									/>
								</Label>
							) : (
								category.description || "—"
							)}
						</dd>
					</>
				) : (
					<>
						<dt className="text-muted-foreground">Config</dt>
						<dd className="text-muted-foreground">
							This category id is not defined under{" "}
							<span className="font-mono">categories</span> in the active
							scoring config. Criteria still reference it.
						</dd>
					</>
				)}
