					<p className="mt-2 text-xs text-muted-foreground">No criteria.</p>
				) : (
					<ul className="mt-2 space-y-1">
						{criteria.map((criterion) => (
							<li key={criterion.id}>
								<Button
									type="button"
									variant="outline"
									size="sm"
									className="h-auto w-full justify-between gap-2 py-1.5 text-left text-xs font-normal"
