								>
									<span className="min-w-0 truncate">{criterion.name}</span>
									<span className="shrink-0 font-mono text-[10px] text-muted-foreground">
										{criterion.id}
									</span>
								</Button>
							</li>
						))}
					</ul>
				)}
			</div>
		</DetailPanelShell>
	);
}

