		return (
			<DetailPanelShell title="Criterion" panelType={panelType}>
				<p className="text-muted-foreground">
					No criterion found for id{" "}
					<span className="font-mono">{criterionId}</span>.
				</p>
			</DetailPanelShell>
		);
	}

	const category = snapshot.activeConfig.categories.find(
		(c) => c.id === criterion.categoryId,
	);

	return (
		<DetailPanelShell title={criterion.name} panelType={panelType}>
			<dl className="grid gap-2 text-xs">
				<dt className="text-muted-foreground">Id</dt>
				<dd className="font-mono text-[11px]">{criterion.id}</dd>
				<dt className="text-muted-foreground">Category</dt>
				<dd>{category?.name ?? criterion.categoryId}</dd>
				<dt className="text-muted-foreground">Measurement basis</dt>
				<dd>{criterion.measurementBasis}</dd>
				<dt className="text-muted-foreground">Description</dt>
				<dd className="text-foreground/90">{criterion.description}</dd>
			</dl>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Scoring rule ({criterion.rule.type})
				</p>
				<pre className="mt-2 whitespace-pre-wrap rounded-md bg-muted/40 p-2 font-mono text-[11px] leading-relaxed text-foreground/90">
					{scoringRuleSummary(criterion.rule)}
				</pre>
			</div>

			<Separator />

			<div>
				<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
					Weight by investment profile (criterion settings)
				</p>
				<ul className="mt-2 space-y-1">
					{snapshot.activeConfig.profiles.map((profile) => {
						const w =
							snapshot.activeConfig.profileWeights[profile.id]?.[
								criterion.id
							] ?? 0;
						return (
							<li
								key={profile.id}
								className="flex justify-between gap-2 rounded-md bg-muted/25 px-2 py-1 text-xs tabular-nums"
							>
								<span className="min-w-0 truncate">{profile.name}</span>
								<span className="shrink-0 font-medium">{w.toFixed(3)}</span>
							</li>
						);
					})}
				</ul>
			</div>

			{canManageData ? (
				<>
					<Separator />
					<p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
						Edit criterion definition
					</p>
					<p className="text-[11px] text-muted-foreground">
						Changes apply to the active scoring config and persist to local
						storage.
					</p>
					<PlotCriteriaEditorPanel
						className="mt-2"
						showCriterionSelector={false}
						criterionOptions={[{ id: criterion.id, name: criterion.name }]}
						selectedCriterionId={criterion.id}
						selectedCriterion={criterion}
						onSelectedCriterionChange={() => {}}
						onCriterionFieldChange={(id, field, value) =>
							void updateCriterionField(id, field, value)
						}
						onRuleTypeChange={(id, type) =>
							void updateCriterionRuleType(id, type)
						}
						onNumericBandChange={(id, bandIndex, field, value) =>
							void updateNumericBand(id, bandIndex, field, value)
						}
						onAddNumericBand={(id) => void addNumericBand(id)}
						onRemoveNumericBand={(id, bandIndex) =>
							void removeNumericBand(id, bandIndex)
						}
						onOptionMappingChange={(id, oldKey, nextKey, nextScore) =>
							void updateOptionMapping(id, oldKey, nextKey, nextScore)
						}
						onAddOptionMapping={(id) => void addOptionMapping(id)}
						onRemoveOptionMapping={(id, key) =>
							void removeOptionMapping(id, key)
						}
						onMultiSelectAggregationChange={(id, aggregation) =>
							void updateMultiSelectAggregation(id, aggregation)
						}
					/>
				</>
			) : null}
		</DetailPanelShell>
	);
}

